351	    const encoded = try protocol.encodeCommandArgs(alloc, &args);
352	    defer alloc.free(encoded);
353	    try std.testing.expectEqualStrings("display-message", encoded[0.."display-message".len]);
354	    try std.testing.expectEqual(@as(u8, 0), encoded["display-message".len]);
