9	/// Message types sent between client and server.
10	pub const MessageType = enum(u16) {
11	    // Client -> Server
12	    identify = 100,
13	    command = 101,
14	    resize = 102,
15	    key = 103,
16	    shell = 104,
17	    exit = 105,
