139	pub fn readExact(fd: std.posix.fd_t, buf: []u8) !void {
140	    var read_total: usize = 0;
141	    while (read_total < buf.len) {
142	        const rc = std.c.read(fd, buf[read_total..].ptr, buf.len - read_total);
143	        if (rc < 0) switch (std.posix.errno(rc)) {
144	            .INTR, .AGAIN => continue,
145	            else => return error.ReadFailed,
146	        };
147	        if (rc == 0) return error.UnexpectedEof;
