195	pub fn encodeCommandArgs(alloc: std.mem.Allocator, args: []const []const u8) ![]u8 {
196	    var total: usize = 0;
197	    for (args) |arg| total += arg.len + 1;
198	    if (total > max_payload) return error.PayloadTooLarge;
199	
200	    const payload = try alloc.alloc(u8, total);
201	    var offset: usize = 0;
202	    for (args) |arg| {
203	        @memcpy(payload[offset .. offset + arg.len], arg);
204	        offset += arg.len;
205	        payload[offset] = 0;
206	        offset += 1;
207	    }
208	    return payload;
209	}
