176	pub fn recvMessageAlloc(alloc: std.mem.Allocator, fd: std.posix.fd_t) !Message {
177	    const header = try recvHeader(fd);
178	    const msg_type = try messageTypeFromInt(header.msg_type);
179	    if (header.payload_len > max_payload) return error.PayloadTooLarge;
180	
181	    const payload = try alloc.alloc(u8, header.payload_len);
182	    errdefer alloc.free(payload);
183	    if (payload.len > 0) {
184	        try readExact(fd, payload);
185	    }
186	
187	    return .{
188	        .msg_type = msg_type,
189	        .flags = header.flags,
190	        .payload = payload,
191	        .allocator = alloc,
192	    };
193	}
