195	pub fn encodeCommandArgs(alloc: std.mem.Allocator, args: []const []const u8) ![]u8 {
196	    var total: usize = 0;
197	    for (args) |arg| total += arg.len + 1;
198	    if (total > max_payload) return error.PayloadTooLarge;
199	
200	    const payload = try alloc.alloc(u8, total);
201	    var offset: usize = 0;
202	    for (args) |arg| {
203	        @memcpy(payload[offset .. offset + arg.len], arg);
204	        offset += arg.len;
205	        payload[offset] = 0;
206	        offset += 1;
207	    }
208	    return payload;
209	}
210	
211	pub fn decodeCommandArgs(alloc: std.mem.Allocator, payload: []const u8) !std.ArrayListAligned([]const u8, null) {
212	    var args: std.ArrayListAligned([]const u8, null) = .empty;
213	    errdefer args.deinit(alloc);
214	
215	    if (payload.len == 0) return args;
216	
217	    var start: usize = 0;
218	    for (payload, 0..) |byte, i| {
219	        if (byte != 0) continue;
220	        try args.append(alloc, payload[start..i]);
221	        start = i + 1;
222	    }
223	
224	    if (start < payload.len) {
225	        try args.append(alloc, payload[start..]);
226	    }
227	
228	    return args;
229	}
