11	/// Screen write context.
12	/// Provides operations to write characters and control sequences to a screen.
13	pub const Writer = struct {
14	    s: *Screen,
15	
16	    pub fn init(s: *Screen) Writer {
17	        return .{ .s = s };
18	    }
