20	    /// Print a character at the current cursor position.
21	    pub fn putChar(self: *Writer, cp: u21) void {
22	        const w = utf8.charWidth(cp);
23	        if (w == 0) return; // skip zero-width for now
24	
25	        // Check if we need to wrap
26	        if (self.s.cx >= self.s.grid.cols) {
27	            if (self.s.mode.wrap) {
28	                self.s.cx = 0;
29	                self.linefeed();
30	            } else {
31	                self.s.cx = self.s.grid.cols -| 1;
32	            }
33	        }
34	
